def count_and_find_numbers_with_digit_sum(A: int, B: int, S: int) -> tuple:
    def digit_sum(n):
        return sum(int(digit) for digit in str(n))

    count = 0
    smallest = None

    for num in range(A, B + 1):
        if digit_sum(num) == S:
            count += 1
            if smallest is None:
                smallest = num

    return (count, smallest)

