def max_spaceship_travel_distance(stars):
    import math

    def dist(a, b):
        # Calculate the minimum angle between a and b in radians
        return min(abs(a - b), 2 * math.pi - abs(a - b))

    def f(angle):
        # Calculate total distance for a given launch angle
        total = 0
        for T, s, a in stars:
            energy = max(0, T - s * dist(a, angle))
            total += energy
        return total

    # Try a range of angles to find the maximum
    max_distance = 0
    for angle in range(0, 628):  # 0 to 2π with step 0.01
        angle_rad = angle / 100
        max_distance = max(max_distance, f(angle_rad))

    # Refine the search around the best angle found
    best_angle = 0
    for angle in range(0, 628):
        angle_rad = angle / 100
        if f(angle_rad) > f(best_angle):
            best_angle = angle_rad

    # Further refinement using binary search or gradient descent could be implemented here

    return f(best_angle)

def longest_interesting_subsequence(n: int, s: int, sequence: list) -> list:
    result = []

    for start in range(n):
        max_length = 0
        for length in range(2, n - start + 1, 2):
            k = length // 2
            first_half_sum = sum(sequence[start:start+k])
            second_half_sum = sum(sequence[start+k:start+length])

            if first_half_sum <= s and second_half_sum <= s:
                max_length = length

        result.append(max_length)

    return result

def plan_sightseeing_trips(n: int, streets: list[tuple[int, int]]) -> list[list[int]]:
    # Build adjacency list
    graph = [[] for _ in range(n)]
    for f, t in streets:
        graph[f].append(t)

    # Check if each node has exactly one outgoing and one incoming edge
    in_degree = [0] * n
    for f, t in streets:
        in_degree[t] += 1

    for i in range(n):
        if len(graph[i]) != in_degree[i]:
            return "Yeah!"  # Cannot form cycles with all nodes

    # Find the cycles
    visited = [False] * n
    trips = []

    for start in range(n):
        if visited[start]:
            continue

        trip = []
        current = start

        while not visited[current]:
            visited[current] = True
            trip.append(current)

            # If this node has no outgoing edges, it's impossible
            if not graph[current]:
                return "Yeah!"

            current = graph[current][0]

            # If we've reached a node we've already visited in another trip
            if visited[current] and current != start:
                return "Yeah!"

        # Check if we've completed a cycle
        if current == start:
            trips.append(trip)
        else:
            # We've reached a node in the current trip, but not the start
            # This means we have a cycle that doesn't include all nodes in the trip
            return "Yeah!"

    return trips

def interpret_basic(program: str) -> str:
    # Parse the program
    statements = {}
    for line in program.strip().split('\n'):
        if not line.strip():
            continue
        parts = line.split(' ', 1)
        label = int(parts[0])
        statement = parts[1]
        statements[label] = statement

    # Initialize variables
    variables = {chr(i): 0 for i in range(ord('A'), ord('Z') + 1)}

    # Execute the program
    output = ""
    labels = sorted(statements.keys())
    current_label_index = 0

    while current_label_index < len(labels):
        current_label = labels[current_label_index]
        statement = statements[current_label]

        if statement.startswith("LET "):
            # Handle LET statement
            assignment = statement[4:].split(" = ")
            var_name = assignment[0]
            expr = assignment[1]

            if "+" in expr:
                operands = expr.split(" + ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                result = (val1 + val2) & 0xFFFFFFFF
                if result > 0x7FFFFFFF:
                    result = result - 0x100000000
            elif "-" in expr:
                operands = expr.split(" - ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                result = (val1 - val2) & 0xFFFFFFFF
                if result > 0x7FFFFFFF:
                    result = result - 0x100000000
            elif "*" in expr:
                operands = expr.split(" * ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                result = (val1 * val2) & 0xFFFFFFFF
                if result > 0x7FFFFFFF:
                    result = result - 0x100000000
            elif "/" in expr:
                operands = expr.split(" / ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                result = val1 // val2 if val1 * val2 >= 0 else -(-val1 // val2)
            else:
                # Single value
                result = variables[expr] if expr.isalpha() else int(expr)

            variables[var_name] = result

        elif statement.startswith("IF "):
            # Handle IF statement
            condition_parts = statement.split(" THEN GOTO ")
            goto_label = int(condition_parts[1])
            condition = condition_parts[0][3:]

            if "=" in condition and "<>" not in condition and "<=" not in condition and ">=" not in condition:
                operands = condition.split(" = ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                if val1 == val2:
                    # Find the index of the goto label
                    for i, label in enumerate(labels):
                        if label == goto_label:
                            current_label_index = i
                            break
                    continue
            elif "<>" in condition:
                operands = condition.split(" <> ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                if val1 != val2:
                    for i, label in enumerate(labels):
                        if label == goto_label:
                            current_label_index = i
                            break
                    continue
            elif "<=" in condition:
                operands = condition.split(" <= ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                if val1 <= val2:
                    for i, label in enumerate(labels):
                        if label == goto_label:
                            current_label_index = i
                            break
                    continue
            elif ">=" in condition:
                operands = condition.split(" >= ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                if val1 >= val2:
                    for i, label in enumerate(labels):
                        if label == goto_label:
                            current_label_index = i
                            break
                    continue
            elif "<" in condition:
                operands = condition.split(" < ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                if val1 < val2:
                    for i, label in enumerate(labels):
                        if label == goto_label:
                            current_label_index = i
                            break
                    continue
            elif ">" in condition:
                operands = condition.split(" > ")
                val1 = variables[operands[0]] if operands[0].isalpha() else int(operands[0])
                val2 = variables[operands[1]] if operands[1].isalpha() else int(operands[1])
                if val1 > val2:
                    for i, label in enumerate(labels):
                        if label == goto_label:
                            current_label_index = i
                            break
                    continue

        elif statement.startswith("PRINT "):
            # Handle PRINT statement
            value = statement[6:]
            if value.startswith('"') and value.endswith('"'):
                output += value[1:-1]
            else:
                output += str(variables[value])

        elif statement.startswith("PRINTLN "):
            # Handle PRINTLN statement
            value = statement[8:]
            if value.startswith('"') and value.endswith('"'):
                output += value[1:-1] + "\n"
            else:
                output += str(variables[value]) + "\n"

        current_label_index += 1

    return output

def count_optimal_paths_of_length_2(n: int, roads: list) -> int:
    # Create an adjacency list representation of the graph
    graph = [[] for _ in range(n + 1)]
    for u, v in roads:
        graph[u].append(v)
        graph[v].append(u)

    # Count optimal paths of length 2
    count = 0

    for i in range(1, n + 1):
        # For each node, count the number of nodes at distance 2
        visited = [False] * (n + 1)
        visited[i] = True

        # Mark all neighbors as visited
        for neighbor in graph[i]:
            visited[neighbor] = True

        # Count valid nodes at distance 2
        for neighbor in graph[i]:
            for next_node in graph[neighbor]:
                if not visited[next_node]:
                    count += 1
                    visited[next_node] = True

    return count

def can_transport_items(w: int, s: int, c: int, k: int) -> bool:
    # If the boat capacity is at least half of the total items, 
    # John can always solve the problem by taking at least half of the items in one go
    if k >= (w + s + c + 1) // 2:
        return True

    # If there are no sheep, wolves and cabbages can be left together
    if s == 0:
        return True

    # If there are no wolves, sheep can't eat cabbages if John takes all sheep first
    if w == 0:
        return k >= s

    # If there are no cabbages, wolves can't eat sheep if John takes all wolves first
    if c == 0:
        return k >= w

    # In general case, if boat capacity is at least the number of wolves or sheep, 
    # John can solve the problem
    if k >= max(w, s):
        return True

    # Otherwise, it's not possible to transport all items without losses
    return False

def find_interception_stations(n: int, links: list, start: int, end: int) -> list:
    import heapq
    from collections import defaultdict

    # Build the graph
    graph = defaultdict(list)
    for u, v, w in links:
        graph[u].append((v, w))

    # Dijkstra to find shortest distances from start to all nodes
    dist_from_start = [float('inf')] * n
    dist_from_start[start] = 0
    pq = [(0, start)]
    while pq:
        dist, node = heapq.heappop(pq)
        if dist > dist_from_start[node]:
            continue
        for neighbor, weight in graph[node]:
            if dist_from_start[neighbor] > dist + weight:
                dist_from_start[neighbor] = dist + weight
                heapq.heappush(pq, (dist + weight, neighbor))

    # Reverse the graph
    reverse_graph = defaultdict(list)
    for u, v, w in links:
        reverse_graph[v].append((u, w))

    # Dijkstra to find shortest distances from end to all nodes (in reversed graph)
    dist_from_end = [float('inf')] * n
    dist_from_end[end] = 0
    pq = [(0, end)]
    while pq:
        dist, node = heapq.heappop(pq)
        if dist > dist_from_end[node]:
            continue
        for neighbor, weight in reverse_graph[node]:
            if dist_from_end[neighbor] > dist + weight:
                dist_from_end[neighbor] = dist + weight
                heapq.heappush(pq, (dist + weight, neighbor))

    # Find the shortest path length from start to end
    shortest_path_length = dist_from_start[end]

    # Find all nodes that lie on some shortest path from start to end
    nodes_on_shortest_paths = []
    for i in range(n):
        if dist_from_start[i] + dist_from_end[i] == shortest_path_length:
            nodes_on_shortest_paths.append(i)

    # Build a subgraph containing only edges on shortest paths
    shortest_graph = defaultdict(list)
    for u, v, w in links:
        if dist_from_start[u] + w + dist_from_end[v] == shortest_path_length:
            shortest_graph[u].append(v)

    # Find articulation points (nodes that, when removed, disconnect start from end)
    result = [start, end]  # Start and end are always on all shortest paths

    for node in nodes_on_shortest_paths:
        if node != start and node != end:
            # Check if removing this node disconnects start from end in the shortest paths subgraph
            visited = [False] * n

            def dfs(curr, avoid):
                if curr == end:
                    return True
                visited[curr] = True
                for neighbor in shortest_graph[curr]:
                    if neighbor != avoid and not visited[neighbor]:
                        if dfs(neighbor, avoid):
                            return True
                return False

            # If we can't reach end from start without passing through node, it's an articulation point
            if not dfs(start, node):
                result.append(node)

    return sorted(result)

def average_operations_before_stop(S: str) -> float:
    n = len(S)
    question_marks = S.count('?')
    total_configs = 2 ** question_marks

    def count_operations(config):
        steps = 0
        while True:
            h_count = config.count('H')
            if h_count == 0:
                return steps
            if h_count <= len(config):
                config = config[:h_count-1] + ('H' if config[h_count-1] == 'T' else 'T') + config[h_count:]
            steps += 1

    total_operations = 0
    for i in range(total_configs):
        # Generate all possible configurations by replacing ? with H or T
        config = ""
        bit_pos = 0
        for c in S:
            if c == '?':
                config += 'H' if (i & (1 << bit_pos)) else 'T'
                bit_pos += 1
            else:
                config += c

        total_operations += count_operations(config)

    return total_operations / total_configs

