def can_keep_permutation_after_swaps(n: int) -> tuple:
    """
    Determines whether it's possible to perform a swap between every pair of positions
    so that the permutation stays the same, and if possible, returns the sequence of swaps.
    """
    if n % 4 > 1:
        return ("NO", [])
    else:
        swaps = []
        for i in range(n % 4, n, 4):
            for x in range(2):
                for j in range(i):
                    swaps.append((j+1, i+2*x+1))
                swaps.append((i+2*x+1, i+2*x+2))
                for j in range(i, 0, -1):
                    swaps.append((j, i+2*x+2))
            swaps.append((i+1, i+4))
            swaps.append((i+2, i+3))
            swaps.append((i+1, i+3))
            swaps.append((i+2, i+4))

        return ("YES", swaps)

def match_visual_python_blocks(n: int, top_left_corners: list, bottom_right_corners: list) -> list:
    # Check if the corners can form valid rectangles
    for i in range(n):
        r1, c1 = top_left_corners[i]
        for j in range(n):
            r2, c2 = bottom_right_corners[j]
            if r1 > r2 or c1 > c2:
                # Top-left corner must be above and to the left of bottom-right corner
                continue

    # Create a bipartite graph where an edge exists if top-left corner i can match with bottom-right corner j
    graph = {}
    for i in range(n):
        r1, c1 = top_left_corners[i]
        graph[i] = []
        for j in range(n):
            r2, c2 = bottom_right_corners[j]
            if r1 < r2 and c1 < c2:
                graph[i].append(j)

    # Try to find a matching using Ford-Fulkerson algorithm
    def dfs(u, visited):
        visited[u] = True
        for v in graph[u]:
            if matching[v] == -1 or (not visited[matching[v]] and dfs(matching[v], visited)):
                matching[v] = u
                return True
        return False

    matching = [-1] * n
    for i in range(n):
        visited = [False] * n
        dfs(i, visited)

    # Check if all vertices are matched
    if -1 in matching:
        return "syntax error"

    # Check if the rectangles are properly nested or disjoint
    for i in range(n):
        r1_i, c1_i = top_left_corners[i]
        r2_i, c2_i = bottom_right_corners[matching.index(i)]
        for j in range(n):
            if i == j:
                continue
            r1_j, c1_j = top_left_corners[j]
            r2_j, c2_j = bottom_right_corners[matching.index(j)]

            # Check if rectangles overlap but are not nested
            if not ((r1_i <= r1_j and c1_i <= c1_j and r2_i >= r2_j and c2_i >= c2_j) or  # i contains j
                   (r1_j <= r1_i and c1_j <= c1_i and r2_j >= r2_i and c2_j >= c2_i) or  # j contains i
                   (r2_i < r1_j or r2_j < r1_i or c2_i < c1_j or c2_j < c1_i)):  # i and j are disjoint
                return "syntax error"

    # Convert to 1-indexed and return the result
    return [matching.index(i) + 1 for i in range(n)]

def count_words_with_hash(N: int, K: int, M: int) -> int:
    MOD = 1 << M

    # dp[i][h] represents the number of words of length i with hash value h
    dp = [{} for _ in range(N + 1)]
    dp[0][0] = 1  # Empty word has hash 0

    for i in range(N):
        for h in dp[i]:
            for letter in range(1, 27):  # 1 to 26 for a to z
                new_hash = ((h * 33) ^ letter) % MOD
                if new_hash not in dp[i + 1]:
                    dp[i + 1][new_hash] = 0
                dp[i + 1][new_hash] += dp[i][h]

    return dp[N].get(K, 0)

def count_valid_answer_sequences(n: int, hints: list) -> int:
    MOD = 10**9 + 7

    # Create a graph where nodes are problems and edges connect problems that must have the same answer
    same_graph = [[] for _ in range(n+1)]
    different_graph = [[] for _ in range(n+1)]

    for l, r, hint_type in hints:
        if hint_type == "same":
            # All problems in range must have same answer
            for i in range(l, r):
                same_graph[i].append(i+1)
                same_graph[i+1].append(i)
        else:  # hint_type == "different"
            # At least one pair in range must be different
            if l == r:
                # Impossible constraint
                return 0
            # We'll handle this differently
            pass

    # Find connected components in the "same" graph
    visited = [False] * (n+1)
    components = []

    def dfs(node, component):
        visited[node] = True
        component.append(node)
        for neighbor in same_graph[node]:
            if not visited[neighbor]:
                dfs(neighbor, component)

    for i in range(1, n+1):
        if not visited[i]:
            component = []
            dfs(i, component)
            components.append(component)

    # Check "different" constraints
    for l, r, hint_type in hints:
        if hint_type == "different":
            # Find all components that have at least one node in the range
            range_components = set()
            for i in range(l, r+1):
                for j, comp in enumerate(components):
                    if i in comp:
                        range_components.add(j)
                        break

            # If there's only one component in the range, the "different" constraint can't be satisfied
            if len(range_components) <= 1:
                return 0

    # Each component can be all true or all false, so 2 possibilities per component
    return pow(2, len(components), MOD)

def count_dinner_experiences(r, s, m, d, n, brands, dishes, incompatible_pairs):
    # Create a graph to represent incompatible dishes
    incompatible = [[] for _ in range(s + m + d + 1)]
    for a, b in incompatible_pairs:
        incompatible[a].append(b)
        incompatible[b].append(a)

    # Find valid combinations of starter, main, and dessert
    valid_combinations = []
    for starter in range(1, s + 1):
        for main in range(s + 1, s + m + 1):
            if main in incompatible[starter]:
                continue
            for dessert in range(s + m + 1, s + m + d + 1):
                if dessert in incompatible[starter] or dessert in incompatible[main]:
                    continue
                valid_combinations.append((starter - 1, main - 1, dessert - 1))

    if not valid_combinations:
        return "0"

    # For each valid combination, calculate the number of ways to choose brands
    total_ways = 0
    for starter, main, dessert in valid_combinations:
        # Combine ingredients from all three dishes
        all_ingredients = set(dishes[starter] + dishes[main] + dishes[dessert])

        # Calculate the number of ways to choose brands
        ways = 1
        for ingredient in all_ingredients:
            ways *= brands[ingredient - 1]
            if ways > 10**18:
                return "too many"

        total_ways += ways
        if total_ways > 10**18:
            return "too many"

    return str(total_ways)

def find_largest_base(age: int, lower_bound: int) -> int:
    def to_base(num, base):
        digits = []
        while num > 0:
            digits.append(num % base)
            num //= base
        return digits[::-1]

    def is_valid(base):
        digits = to_base(age, base)
        if any(d > 9 for d in digits):
            return False

        base_10_value = sum(d * (10 ** i) for i, d in enumerate(digits[::-1]))
        return base_10_value >= lower_bound

    # Binary search for the largest valid base
    left, right = 10, age + 1
    while left < right:
        mid = (left + right) // 2
        if is_valid(mid):
            left = mid + 1
        else:
            right = mid

    return left - 1

def min_offers_to_paint_fence(offers):
    # Convert offers to a standardized format
    offers_list = [(color, start, end) for color, start, end in offers]

    # Check if all sections are covered
    def is_covered(selected_offers):
        covered = [False] * 10001  # 1-indexed
        for _, start, end in selected_offers:
            for i in range(start, end + 1):
                covered[i] = True
        return all(covered[1:10001])

    # Try all combinations of up to 3 colors
    all_colors = set(color for color, _, _ in offers_list)
    if len(all_colors) <= 3:
        # If we have at most 3 colors, try to cover with these
        selected_offers = offers_list
        if is_covered(selected_offers):
            # Find minimum number of offers needed
            min_offers = float('inf')

            def backtrack(idx, current_offers):
                nonlocal min_offers

                if idx == len(selected_offers):
                    if is_covered(current_offers):
                        min_offers = min(min_offers, len(current_offers))
                    return

                # Include current offer
                backtrack(idx + 1, current_offers + [selected_offers[idx]])

                # Exclude current offer
                backtrack(idx + 1, current_offers)

            backtrack(0, [])
            return min_offers if min_offers != float('inf') else "IMPOSSIBLE"

    # Try all combinations of exactly 3 colors
    from itertools import combinations

    min_offers = float('inf')
    for three_colors in combinations(all_colors, min(3, len(all_colors))):
        color_set = set(three_colors)
        valid_offers = [offer for offer in offers_list if offer[0] in color_set]

        # Check if these offers can cover the fence
        if is_covered(valid_offers):
            # Find minimum number of offers needed with these colors
            min_offers_for_combo = float('inf')

            def backtrack(idx, current_offers):
                nonlocal min_offers_for_combo

                if len(current_offers) >= min_offers_for_combo:
                    return

                if idx == len(valid_offers):
                    if is_covered(current_offers):
                        min_offers_for_combo = min(min_offers_for_combo, len(current_offers))
                    return

                # Include current offer
                backtrack(idx + 1, current_offers + [valid_offers[idx]])

                # Exclude current offer
                backtrack(idx + 1, current_offers)

            backtrack(0, [])

            if min_offers_for_combo != float('inf'):
                min_offers = min(min_offers, min_offers_for_combo)

    return min_offers if min_offers != float('inf') else "IMPOSSIBLE"

def max_sets_played(k: int, a: int, b: int) -> int:
    mx_a = a // k
    mx_b = b // k
    if mx_a == 0 and b % k != 0:
        return -1
    elif mx_b == 0 and a % k != 0:
        return -1
    else:
        return mx_a + mx_b

def largest_square_killer(memory: list[str]) -> int:
    rows = len(memory)
    cols = len(memory[0])

    # Function to check if a square with top-left corner at (i, j) and size 'size' is a killer
    def is_killer(i, j, size):
        for r in range(size):
            for c in range(size):
                if memory[i+r][j+c] != memory[i+size-1-r][j+size-1-c]:
                    return False
        return True

    max_size = -1

    # Check all possible squares
    for size in range(2, min(rows, cols) + 1):  # Start from size 2 as we need more than one character
        for i in range(rows - size + 1):
            for j in range(cols - size + 1):
                if is_killer(i, j, size):
                    max_size = size

    return max_size

def find_best_word_to_add(words: list) -> tuple:
    from collections import deque, defaultdict

    # Extract start and end words
    start = words[0]
    end = words[1]
    word_length = len(start)

    # Create a set of all words in the dictionary
    dictionary = set(words)

    # Function to find all possible words that differ by one letter
    def get_neighbors(word):
        neighbors = []
        for i in range(word_length):
            for c in "ABCDEFGHIJKLMNOPQRSTUVWXYZ":
                if c != word[i]:
                    new_word = word[:i] + c + word[i+1:]
                    neighbors.append(new_word)
        return neighbors

    # Function to find shortest path length using BFS
    def find_shortest_path(dictionary, start, end):
        if start == end:
            return 0

        visited = set([start])
        queue = deque([(start, 0)])

        while queue:
            word, distance = queue.popleft()

            for neighbor in get_neighbors(word):
                if neighbor == end:
                    return distance + 1
                if neighbor in dictionary and neighbor not in visited:
                    visited.add(neighbor)
                    queue.append((neighbor, distance + 1))

        return -1  # No path found

    # Find current shortest path length
    current_path_length = find_shortest_path(dictionary, start, end)

    # If there's already a path, we need to check if we can make it shorter
    if current_path_length != -1:
        return ("0", current_path_length)

    # Try adding each possible word and see if it makes a path possible or shorter
    potential_words = []
    all_possible_words = set()

    # Generate all possible words by changing one letter at a time
    for word in dictionary:
        for neighbor in get_neighbors(word):
            if neighbor not in dictionary:
                all_possible_words.add(neighbor)

    for new_word in sorted(all_possible_words):
        # Skip words already in the dictionary
        if new_word in dictionary:
            continue

        # Add the new word to the dictionary temporarily
        new_dictionary = dictionary.copy()
        new_dictionary.add(new_word)

        # Check if there's a path now
        path_length = find_shortest_path(new_dictionary, start, end)

        if path_length != -1:
            return (new_word, path_length)

    # If we reach here, no word can be added to make a path
    return ("0", -1)

def min_cache_loads(c: int, n: int, accesses: list[int]) -> int:
    if not accesses:
        return 0

    # For each object, find when it will be accessed next
    next_access = {}
    for i in range(len(accesses) - 1, -1, -1):
        obj = accesses[i]
        next_access[i] = next_access.get(obj, float('inf'))
        next_access[obj] = i

    cache = set()
    loads = 0

    for i, obj in enumerate(accesses):
        if obj not in cache:
            loads += 1
            if len(cache) == c:  # Cache is full, need to evict
                # Find object in cache that will be used furthest in the future
                to_evict = None
                furthest = -1
                for cached_obj in cache:
                    next_use = float('inf')
                    for j in range(i + 1, len(accesses)):
                        if accesses[j] == cached_obj:
                            next_use = j
                            break
                    if next_use > furthest:
                        furthest = next_use
                        to_evict = cached_obj
                cache.remove(to_evict)
            cache.add(obj)

    return loads

def probability_of_finding_key(array: list) -> str:
    MOD = 10**9 + 7

    def fpow(a, n):
        if n == 0:
            return 1
        elif n & 1 == 1:
            return (a * fpow(a, n - 1)) % MOD
        else:
            t = fpow(a, n >> 1)
            return (t * t) % MOD

    class Matrix:
        def __init__(self, n, m, arr=None):
            self.n = n
            self.m = m
            self.arr = [[0] * m for i in range(n)]
            if arr is not None:
                for i in range(n):
                    for j in range(m):
                        self.arr[i][j] = arr[i][j]

        def __mul__(self, other):
            assert self.m == other.n
            ans = Matrix(self.n, other.m)
            for i in range(self.n):
                for j in range(other.m):
                    for k in range(self.m):
                        ans.arr[i][j] = (ans.arr[i][j] + self.arr[i][k] * other.arr[k][j]) % MOD
            return ans

        def __pow__(self, n):
            if n == 0:
                ans = Matrix(self.n, self.n)
                for i in range(self.n):
                    ans.arr[i][i] = 1
                return ans
            elif n & 1 == 1:
                return self * (self ** (n - 1))
            else:
                t = self ** (n >> 1)
                return t * t

    transform = Matrix(2, 2, [[1, 1], [0, 4]])

    # Calculate x = product of all elements mod (10^9 + 6)
    x = 1
    for j in array:
        x = (x * j) % (MOD - 1)

    # Adjust x to be the number of turns - 1
    x = (x - 1) % (MOD - 1)

    if x % 2 == 0:
        ans = (transform ** (x // 2)) * Matrix(2, 1, [[0], [1]])
        return f"{ans.arr[0][0]}/{fpow(2, x)}"
    else:
        y = (x - 1) % (MOD - 1)
        ans = (transform ** (y // 2)) * Matrix(2, 1, [[0], [1]])
        p = (ans.arr[0][0] * 2 + 1) % MOD
        q = (ans.arr[1][0] * 2) % MOD
        return f"{p}/{q}"

def decipher_text(text: str, dictionary: list) -> str:
    # For each word in the dictionary, determine its signature
    # A signature is the first letter, last letter, and sorted middle letters
    signatures = {}
    for word in dictionary:
        if len(word) <= 2:
            sig = word
        else:
            middle = ''.join(sorted(word[1:-1]))
            sig = word[0] + middle + word[-1]

        if sig not in signatures:
            signatures[sig] = []
        signatures[sig].append(word)

    # Try to find a valid segmentation of the text
    n = len(text)

    # dp[i] will store all possible segmentations up to position i
    dp = [[] for _ in range(n+1)]
    dp[0] = [[]]  # Empty segmentation for the empty prefix

    for i in range(1, n+1):
        for j in range(i):
            if not dp[j]:
                continue

            segment = text[j:i]
            if len(segment) <= 2:
                sig = segment
            else:
                middle = ''.join(sorted(segment[1:-1]))
                sig = segment[0] + middle + segment[-1]

            if sig in signatures:
                for word in signatures[sig]:
                    for prev_segmentation in dp[j]:
                        dp[i].append(prev_segmentation + [word])

    # Check if we have a unique segmentation
    if not dp[n]:
        return "impossible"
    elif len(dp[n]) > 1:
        return "ambiguous"
    else:
        return " ".join(dp[n][0])

