def determine_shopping_path(num_stores: int, store_inventory: list, purchased_items: list) -> str:
    # Create a mapping from item to the stores that sell it
    item_to_stores = {}
    for store_id, item in store_inventory:
        if item not in item_to_stores:
            item_to_stores[item] = []
        item_to_stores[item].append(store_id)

    # Check if all purchased items are available
    for item in purchased_items:
        if item not in item_to_stores:
            return "impossible"

    # Try to find a valid path
    def backtrack(item_index, current_store, path):
        if item_index == len(purchased_items):
            return [path]

        item = purchased_items[item_index]
        valid_paths = []

        # Try all stores that sell this item
        for store_id in item_to_stores[item]:
            # We can only move forward in store order
            if store_id >= current_store:
                new_paths = backtrack(item_index + 1, store_id, path + [store_id])
                valid_paths.extend(new_paths)

                # Early termination if we find multiple paths
                if len(valid_paths) > 1:
                    return valid_paths

        return valid_paths

    valid_paths = backtrack(0, 0, [])

    if not valid_paths:
        return "impossible"
    elif len(valid_paths) == 1:
        return "unique"
    else:
        return "ambiguous"

def latest_departure_time(n: int, m: int, meeting_time: int, tram_lines: list) -> int:
    import heapq
    from collections import defaultdict

    # Build graph
    graph = defaultdict(list)
    for u, v, t_0, p, d in tram_lines:
        graph[u].append((v, t_0, p, d))

    # Initialize distances
    dist = [float('inf')] * n
    dist[0] = 0

    # Dijkstra's algorithm with priority queue
    pq = [(0, 0)]  # (time, stop)
    while pq:
        time, stop = heapq.heappop(pq)

        if time > dist[stop]:
            continue

        if stop == n - 1:
            break

        for next_stop, t_0, p, d in graph[stop]:
            # Find the next departure time after current time
            if time <= t_0:
                next_time = t_0 + d
            else:
                wait = (time - t_0 + p - 1) // p * p
                next_time = t_0 + wait + d

            if next_time < dist[next_stop]:
                dist[next_stop] = next_time
                heapq.heappush(pq, (next_time, next_stop))

    # Check if we can reach the meeting on time
    if dist[n-1] <= meeting_time:
        # Calculate the latest departure time
        latest_time = meeting_time - dist[n-1]
        return latest_time
    else:
        return "impossible"

