def count_activated_pixels(pulses):
    activated = set()

    # Group pulses by direction
    h_pulses = []
    v_pulses = []
    for direction, start_time, length, wire_number in pulses:
        if direction == 'h':
            h_pulses.append((start_time, length, wire_number))
        else:  # direction == 'v'
            v_pulses.append((start_time, length, wire_number))

    # Check each pair of horizontal and vertical pulses
    for h_start, h_length, h_wire in h_pulses:
        for v_start, v_length, v_wire in v_pulses:
            # Calculate when the pulses reach the intersection
            h_reach_time = h_start + v_wire - 1
            v_reach_time = v_start + h_wire - 1

            # Calculate when the pulses leave the intersection
            h_leave_time = h_reach_time + h_length
            v_leave_time = v_reach_time + v_length

            # Check if the pulses overlap at the intersection
            if h_reach_time < v_leave_time and v_reach_time < h_leave_time:
                activated.add((h_wire, v_wire))

    return len(activated)

def count_sequences_with_confusion(n: int, c: int) -> int:
    MOD = 10**9 + 7

    # If confusion is too large, no valid sequence exists
    if c > n * (n - 1) // 2:
        return 0

    # dp[i][j] = number of sequences of length i with confusion j
    dp = [[0] * (c + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(c + 1):
            for k in range(i):
                # If we place the number i at position k, it creates (i-1-k) confused pairs
                if j >= i - 1 - k:
                    dp[i][j] = (dp[i][j] + dp[i-1][j-(i-1-k)]) % MOD

    return dp[n][c]

def count_valid_rankings(names):
    MOD = 10**9 + 7

    # Build trie structure from names
    trie = {}
    for name in names:
        node = trie
        for c in name:
            if c not in node:
                node[c] = {}
            node = node[c]
        node['$'] = True  # Mark end of word

    # Calculate factorial for later use
    def factorial(n):
        result = 1
        for i in range(2, n + 1):
            result = (result * i) % MOD
        return result

    # Recursive function to count valid orderings in a subtree
    def count_orderings(node):
        if not node:
            return 1

        # Count leaf nodes (names ending at this node)
        leaf_count = 1 if '$' in node else 0

        # Count valid orderings for each child branch
        child_results = []
        total_children = 0

        for c in node:
            if c != '$':
                child_count = count_orderings(node[c])
                child_results.append(child_count)
                total_children += 1

        # Calculate the number of ways to interleave the child branches
        ways = factorial(total_children)

        # Multiply by the number of ways for each child branch
        result = ways
        for count in child_results:
            result = (result * count) % MOD

        # If this node has both leaf nodes and child branches,
        # we need to consider where to place the leaf nodes
        if leaf_count > 0 and total_children > 0:
            result = (result * (total_children + 1)) % MOD

        return result

    return count_orderings(trie)

