def recover_matrix(row_parities: str, col_parities: str) -> list:
    n = len(row_parities)
    m = len(col_parities)

    # Check if recovery is possible
    row_parity_sum = sum(int(r) for r in row_parities)
    col_parity_sum = sum(int(c) for c in col_parities)

    if row_parity_sum % 2 != col_parity_sum % 2:
        return ["-1"]

    # Initialize matrix with all 1s
    matrix = [['1' for _ in range(m)] for _ in range(n)]

    # Calculate current parities
    current_row_parities = [0] * n
    current_col_parities = [0] * m

    for i in range(n):
        for j in range(m):
            current_row_parities[i] = (current_row_parities[i] + 1) % 2
            current_col_parities[j] = (current_col_parities[j] + 1) % 2

    # Fix parities by flipping entries
    for i in range(n - 1):
        for j in range(m - 1):
            target_row_parity = int(row_parities[i])
            target_col_parity = int(col_parities[j])

            if current_row_parities[i] != target_row_parity and current_col_parities[j] != target_col_parity:
                # Flip this entry
                matrix[i][j] = '0'
                current_row_parities[i] = target_row_parity
                current_col_parities[j] = target_col_parity

    # Check if last row and column can be fixed
    for i in range(n - 1):
        target_row_parity = int(row_parities[i])
        if current_row_parities[i] != target_row_parity:
            # Flip the entry in the last column
            matrix[i][m - 1] = '0'

    for j in range(m - 1):
        target_col_parity = int(col_parities[j])
        if current_col_parities[j] != target_col_parity:
            # Flip the entry in the last row
            matrix[n - 1][j] = '0'

    # Handle the bottom-right corner
    bottom_right_parity = 0
    for i in range(n - 1):
        if matrix[i][m - 1] == '1':
            bottom_right_parity = (bottom_right_parity + 1) % 2

    for j in range(m - 1):
        if matrix[n - 1][j] == '1':
            bottom_right_parity = (bottom_right_parity + 1) % 2

    target_bottom_right_parity = (int(row_parities[n - 1]) + int(col_parities[m - 1])) % 2
    if bottom_right_parity != target_bottom_right_parity:
        matrix[n - 1][m - 1] = '0'

    # Convert matrix to list of strings
    return [''.join(row) for row in matrix]

