        if expr.startswith('`') and expr.endswith('`'):
            template = expr[1:-1]
            result = ""
            i = 0
            while i < len(template):
                if i + 1 < len(template) and template[i:i+2] == "${":
                    # Find the matching closing brace
                    brace_count = 1
                    j = i + 2
                    while j < len(template) and brace_count > 0:
                        if template[j] == '{':
                            brace_count += 1
                        elif template[j] == '}':
                            brace_count -= 1
                        j += 1

                    if brace_count == 0:
                        embedded_expr = template[i+2:j-1]
                        result += evaluate_expression(embedded_expr)
                        i = j
                    else:
                        result += template[i]
                        i += 1
                else:
                    result += template[i]
                    i += 1
            return result

        return expr  # Default case

    for line in lines:
        if line == "end.":
            break

        if line.startswith("var "):
            # Variable declaration
            parts = line.strip(";").split(" = ", 1)
            var_name = parts[0][4:]  # Remove "var " prefix
            var_value = evaluate_expression(parts[1])
            variables[var_name] = var_value

        elif line.startswith("print "):
            # Print statement
            expr = line[6:].strip(";")
            result = evaluate_expression(expr)
            results.append(result)

    return results

def sabotage_list(numbers: list) -> list:
    n = len(numbers)

    # Try to increase a number to make it larger than the next number
    for i in range(n-1):
        if numbers[i] == numbers[i+1]:
            # If two consecutive numbers are equal, we can increase the first one
            num_str = str(numbers[i])
            for j in range(len(num_str)):
                for d in range(int(num_str[j])+1, 10):
                    new_num_str = num_str[:j] + str(d) + num_str[j+1:]
                    new_num = int(new_num_str)
                    result = numbers.copy()
                    result[i] = new_num
                    return result

    # Try to decrease a number to make it smaller than the previous number
    for i in range(1, n):
        num_str = str(numbers[i])
        for j in range(len(num_str)):
            # Cannot create a leading zero
            if j == 0 and len(num_str) > 1 and int(num_str[j]) > 0:
                for d in range(0, int(num_str[j])):
                    if d > 0:  # Avoid leading zeros
                        new_num_str = str(d) + num_str[1:]
                        new_num = int(new_num_str)
                        if new_num < numbers[i-1]:
                            result = numbers.copy()
                            result[i] = new_num
                            return result
            elif j > 0 or len(num_str) == 1:
                for d in range(0, int(num_str[j])):
                    new_num_str = num_str[:j] + str(d) + num_str[j+1:]
                    new_num = int(new_num_str)
                    if new_num < numbers[i-1]:
                        result = numbers.copy()
                        result[i] = new_num
                        return result

    # Try to increase a number to make it larger than all subsequent numbers
    for i in range(n-1):
        num_str = str(numbers[i])
        for j in range(len(num_str)):
            for d in range(int(num_str[j])+1, 10):
                new_num_str = num_str[:j] + str(d) + num_str[j+1:]
                new_num = int(new_num_str)
                if new_num > numbers[-1]:
                    result = numbers.copy()
                    result[i] = new_num
                    return result

    # Try to decrease a number to make it smaller than all previous numbers
    for i in range(1, n):
        num_str = str(numbers[i])
        for j in range(len(num_str)):
            # Cannot create a leading zero
            if j == 0 and len(num_str) > 1:
                continue
            for d in range(0, int(num_str[j])):
                new_num_str = num_str[:j] + str(d) + num_str[j+1:]
                new_num = int(new_num_str)
                if new_num < numbers[0]:
                    result = numbers.copy()
                    result[i] = new_num
                    return result

    return "impossible"

def max_partition_score(n: int, k: int, sequence: list) -> int:
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    def gcd(a, b):
        while b:
            a, b = b, a % b
        return a

    def get_largest_common_prime_divisor(nums):
        if not nums:
            return 0

        # Find GCD of all numbers in the region
        curr_gcd = nums[0]
        for num in nums[1:]:
            curr_gcd = gcd(curr_gcd, num)

        # Find the largest prime divisor of the GCD
        largest_prime = 0
        i = 2
        while i * i <= curr_gcd:
            if curr_gcd % i == 0:
                if is_prime(i):
                    largest_prime = max(largest_prime, i)
                if is_prime(curr_gcd // i):
                    largest_prime = max(largest_prime, curr_gcd // i)
            i += 1

        if curr_gcd > 1 and is_prime(curr_gcd):
            largest_prime = max(largest_prime, curr_gcd)

        return largest_prime

    # Initialize dp array
    dp = [[float('-inf') for _ in range(k+1)] for _ in range(n+1)]
    dp[0][0] = float('inf')

    # Precompute largest common prime divisors for all possible subarrays
    largest_primes = [[0 for _ in range(n+1)] for _ in range(n+1)]
    for i in range(n):
        for j in range(i, n):
            largest_primes[i][j] = get_largest_common_prime_divisor(sequence[i:j+1])

    # Fill dp array
    for i in range(1, n+1):
        for j in range(1, min(i, k)+1):
            for prev in range(j-1, i):
                score = min(dp[prev][j-1], largest_primes[prev][i-1])
                dp[i][j] = max(dp[i][j], score)

    return dp[n][k]

def find_transportation_costs(n, roads, queries):
    import heapq

    # Build adjacency list
    graph = [[] for _ in range(n + 1)]
    for a, b, w in roads:
        graph[a].append((b, w))
        graph[b].append((a, w))

    def dijkstra(start, end):
        # Initialize distances with infinity
        distances = [float('inf')] * (n + 1)
        distances[start] = 0

        # Priority queue for Dijkstra's algorithm
        pq = [(0, start)]

        while pq:
            dist, node = heapq.heappop(pq)

            if node == end:
                return dist

            if dist > distances[node]:
                continue

            for neighbor, weight in graph[node]:
                new_dist = dist | weight  # Bitwise OR

                if new_dist < distances[neighbor]:
                    distances[neighbor] = new_dist
                    heapq.heappush(pq, (new_dist, neighbor))

        return distances[end]

    results = []
    for s, t in queries:
        results.append(dijkstra(s, t))

    return results

def traffic_light_probability(t_g: int, t_y: int, t_r: int, observations: list, query_time: int, query_color: str) -> float:
    cycle_length = t_g + t_y + t_r

    # Define possible start times for the cycle
    # Initially all values from 0 to cycle_length-1 are possible
    possible_starts = set(range(cycle_length))

    # Process each observation
    for time, color in observations:
        remaining_starts = set()

        for start in possible_starts:
            # Calculate position in cycle
            position_in_cycle = (time - start) % cycle_length

            # Check if this start time is consistent with the observation
            if color == "green" and position_in_cycle < t_g:
                remaining_starts.add(start)
            elif color == "yellow" and t_g <= position_in_cycle < t_g + t_y:
                remaining_starts.add(start)
            elif color == "red" and t_g + t_y <= position_in_cycle < cycle_length:
                remaining_starts.add(start)

        possible_starts = remaining_starts

    # Count how many start times result in the query color at query time
    count = 0
    for start in possible_starts:
        position_in_cycle = (query_time - start) % cycle_length

        if query_color == "green" and position_in_cycle < t_g:
            count += 1
        elif query_color == "yellow" and t_g <= position_in_cycle < t_g + t_y:
            count += 1
        elif query_color == "red" and t_g + t_y <= position_in_cycle < cycle_length:
            count += 1

    # Calculate probability
    if len(possible_starts) == 0:
        return 0.0
    return count / len(possible_starts)

def can_hit_all_targets_with_two_shots(targets):
    n = len(targets)

    # If there are 0 or 1 targets, we can hit all of them with at most 2 shots
    if n <= 2:
        return "success"

    # Check if all targets lie on a single line
    if n >= 3:
        # Function to check if three points are collinear
        def are_collinear(p1, p2, p3):
            return (p2[1] - p1[1]) * (p3[0] - p2[0]) == (p3[1] - p2[1]) * (p2[0] - p1[0])

        # Check if all points lie on the same line with the first two points
        if n >= 3:
            all_collinear = True
            for i in range(2, n):
                if not are_collinear(targets[0], targets[1], targets[i]):
                    all_collinear = False
                    break
            if all_collinear:
                return "success"

    # Try to find a pair of lines that cover all points
    for i in range(n):
        for j in range(i+1, n):
            # Create a line through points i and j
            line1_points = set()
            line1_points.add(i)
            line1_points.add(j)

            for k in range(n):
                if k != i and k != j and are_collinear(targets[i], targets[j], targets[k]):
                    line1_points.add(k)

            # If we've already covered all points with one line
            if len(line1_points) == n:
                return "success"

            # Try to find another line that covers the remaining points
            remaining_points = set(range(n)) - line1_points

            if len(remaining_points) <= 2:
                # If there are 0, 1, or 2 remaining points, we can hit them with a second shot
                return "success"

            # Check if all remaining points are collinear
            remaining_list = list(remaining_points)
            all_remaining_collinear = True
            for k in range(2, len(remaining_list)):
                if not are_collinear(targets[remaining_list[0]], targets[remaining_list[1]], targets[remaining_list[k]]):
                    all_remaining_collinear = False
                    break

            if all_remaining_collinear:
                return "success"

    return "failure"

def lowest_grade_challenge24(base_values: list) -> str:
    from itertools import permutations, product

    # All possible operations
    ops = ['+', '-', '*', '/']

    # Function to evaluate an expression
    def evaluate(nums, operations, parentheses):
        # Apply parentheses first
        if parentheses == 0:  # (a op b) op c op d
            try:
                if operations[0] == '+':
                    result = nums[0] + nums[1]
                elif operations[0] == '-':
                    result = nums[0] - nums[1]
                elif operations[0] == '*':
                    result = nums[0] * nums[1]
                elif operations[0] == '/':
                    if nums[1] == 0 or nums[0] % nums[1] != 0:
                        return None
                    result = nums[0] // nums[1]

                for i in range(2, 4):
                    if operations[i-1] == '+':
                        result += nums[i]
                    elif operations[i-1] == '-':
                        result -= nums[i]
                    elif operations[i-1] == '*':
                        result *= nums[i]
                    elif operations[i-1] == '/':
                        if nums[i] == 0 or result % nums[i] != 0:
                            return None
                        result //= nums[i]
            except:
                return None

        elif parentheses == 1:  # a op (b op c) op d
            try:
                if operations[1] == '+':
                    inner_result = nums[1] + nums[2]
                elif operations[1] == '-':
                    inner_result = nums[1] - nums[2]
                elif operations[1] == '*':
                    inner_result = nums[1] * nums[2]
                elif operations[1] == '/':
                    if nums[2] == 0 or nums[1] % nums[2] != 0:
                        return None
                    inner_result = nums[1] // nums[2]

                if operations[0] == '+':
