                elif operations[0] == '*':
                    result = nums[0] * inner_result
                elif operations[0] == '/':
                    if inner_result == 0 or nums[0] % inner_result != 0:
                        return None
                    result = nums[0] // inner_result

                if operations[2] == '+':
                    result += nums[3]
                elif operations[2] == '-':
                    result -= nums[3]
                elif operations[2] == '*':
                    result *= nums[3]
                elif operations[2] == '/':
                    if nums[3] == 0 or result % nums[3] != 0:
                        return None
                    result //= nums[3]
            except:
                return None

        elif parentheses == 2:  # a op b op (c op d)
            try:
                if operations[2] == '+':
                    inner_result = nums[2] + nums[3]
                elif operations[2] == '-':
                    inner_result = nums[2] - nums[3]
                elif operations[2] == '*':
                    inner_result = nums[2] * nums[3]
                elif operations[2] == '/':
                    if nums[3] == 0 or nums[2] % nums[3] != 0:
                        return None
                    inner_result = nums[2] // nums[3]

                result = nums[0]
                if operations[0] == '+':
                    result += nums[1]
                elif operations[0] == '-':
                    result -= nums[1]
                elif operations[0] == '*':
                    result *= nums[1]
                elif operations[0] == '/':
                    if nums[1] == 0 or nums[0] % nums[1] != 0:
                        return None
                    result //= nums[1]

                if operations[1] == '+':
                    result += inner_result
                elif operations[1] == '-':
                    result -= inner_result
                elif operations[1] == '*':
                    result *= inner_result
                elif operations[1] == '/':
                    if inner_result == 0 or result % inner_result != 0:
                        return None
                    result //= inner_result
            except:
                return None

        elif parentheses == 3:  # (a op b op c) op d
            try:
                result = nums[0]
                if operations[0] == '+':
                    result += nums[1]
                elif operations[0] == '-':
                    result -= nums[1]
                elif operations[0] == '*':
                    result *= nums[1]
                elif operations[0] == '/':
                    if nums[1] == 0 or nums[0] % nums[1] != 0:
                        return None
                    result //= nums[1]

                if operations[1] == '+':
                    result += nums[2]
                elif operations[1] == '-':
                    result -= nums[2]
                elif operations[1] == '*':
                    result *= nums[2]
                elif operations[1] == '/':
                    if nums[2] == 0 or result % nums[2] != 0:
                        return None
                    result //= nums[2]

                if operations[2] == '+':
                    result += nums[3]
                elif operations[2] == '-':
                    result -= nums[3]
                elif operations[2] == '*':
                    result *= nums[3]
                elif operations[2] == '/':
                    if nums[3] == 0 or result % nums[3] != 0:
                        return None
                    result //= nums[3]
            except:
                return None

        elif parentheses == 4:  # a op (b op c op d)
            try:
                inner_result = nums[1]
                if operations[1] == '+':
                    inner_result += nums[2]
                elif operations[1] == '-':
                    inner_result -= nums[2]
                elif operations[1] == '*':
                    inner_result *= nums[2]
                elif operations[1] == '/':
                    if nums[2] == 0 or inner_result % nums[2] != 0:
                        return None
                    inner_result //= nums[2]

                if operations[2] == '+':
                    inner_result += nums[3]
                elif operations[2] == '-':
                    inner_result -= nums[3]
                elif operations[2] == '*':
                    inner_result *= nums[3]
                elif operations[2] == '/':
                    if nums[3] == 0 or inner_result % nums[3] != 0:
                        return None
                    inner_result //= nums[3]

                if operations[0] == '+':
                    result = nums[0] + inner_result
                elif operations[0] == '-':
                    result = nums[0] - inner_result
                elif operations[0] == '*':
                    result = nums[0] * inner_result
                elif operations[0] == '/':
                    if inner_result == 0 or nums[0] % inner_result != 0:
                        return None
                    result = nums[0] // inner_result
            except:
                return None

        return result

    # Count inversions in a permutation
    def count_inversions(perm, original):
        # Create a mapping from value to index in the original list
        value_to_index = {val: i for i, val in enumerate(original)}

        # Convert the permutation to indices in the original list
        perm_indices = [value_to_index[val] for val in perm]

        # Count inversions (swaps needed to sort)
        inversions = 0
        for i in range(len(perm_indices)):
            for j in range(i+1, len(perm_indices)):
                if perm_indices[i] > perm_indices[j]:
                    inversions += 1

        return inversions

    best_grade = float('inf')

    # Try all permutations of the base values
    for perm in permutations(base_values):
        # Calculate inversions for this permutation
        inv_count = count_inversions(perm, base_values)
        inversions_grade = 2 * inv_count

        # If the grade from inversions alone is already worse than our best, skip
        if inversions_grade >= best_grade:
            continue

        # Try all combinations of operations
        for ops_combo in product(ops, repeat=3):
            # Try different parentheses placements (0 to 4 represent different placements)
            for paren in range(5):
                # The grade is inversions_grade + number of parentheses used
                grade = inversions_grade + (1 if paren > 0 else 0)

                # If this grade is already worse than our best, skip
                if grade >= best_grade:
                    continue

                # Evaluate the expression
                result = evaluate(perm, ops_combo, paren)

                # If we got 24, update the best grade
                if result == 24:
                    best_grade = grade

    return str(best_grade) if best_grade != float('inf') else "impossible"

def find_alphabet_order(max_char: str, word_list: list) -> str:
    from collections import defaultdict, deque

    # Create a graph where nodes are characters and edges represent ordering constraints
    graph = defaultdict(set)
    in_degree = defaultdict(int)

    # Initialize all characters from 'a' to max_char
    chars = set()
    for word in word_list:
        for char in word:
            chars.add(char)

    # Add edges based on adjacent words in the list
    for i in range(len(word_list) - 1):
        word1 = word_list[i]
        word2 = word_list[i + 1]

        # Find the first differing character
        min_len = min(len(word1), len(word2))
        for j in range(min_len):
            if word1[j] != word2[j]:
                if word2[j] not in graph[word1[j]]:
                    graph[word1[j]].add(word2[j])
                    in_degree[word2[j]] += 1
                break
            # Check if word1 is a prefix of word2
            elif j == min_len - 1 and len(word1) > len(word2):
                return "IMPOSSIBLE"  # Inconsistent ordering

    # Perform topological sort
    queue = deque([c for c in chars if in_degree[c] == 0])
    result = []

    while queue:
        if len(queue) > 1:
            return "AMBIGUOUS"  # Multiple valid orderings possible

        char = queue.popleft()
        result.append(char)

        for next_char in graph[char]:
            in_degree[next_char] -= 1
            if in_degree[next_char] == 0:
                queue.append(next_char)

    # Check if we found a valid ordering for all characters
    if len(result) != len(chars):
        return "IMPOSSIBLE"  # Cycle detected

    return ''.join(result)

def can_build_spanning_tree(n: int, edges: list, k: int) -> int:
    import heapq

    # Create adjacency list
    graph = [[] for _ in range(n + 1)]
    for c, u, v in edges:
        graph[u].append((v, c == 'B'))
        graph[v].append((u, c == 'B'))

    # Kruskal's algorithm with modifications
    blue_edges = []
    red_edges = []

    for c, u, v in edges:
        if c == 'B':
            blue_edges.append((u, v))
        else:
            red_edges.append((u, v))

    # Function to find parent (for Union-Find)
    def find(parent, x):
        if parent[x] != x:
            parent[x] = find(parent, parent[x])
        return parent[x]

    # Function to union two sets
    def union(parent, rank, x, y):
        root_x = find(parent, x)
        root_y = find(parent, y)

        if root_x == root_y:
            return False

        if rank[root_x] < rank[root_y]:
            parent[root_x] = root_y
        elif rank[root_x] > rank[root_y]:
            parent[root_y] = root_x
        else:
            parent[root_y] = root_x
            rank[root_x] += 1

        return True

    # Count maximum possible blue edges in MST
    parent = list(range(n + 1))
    rank = [0] * (n + 1)

    blue_count = 0
    for u, v in blue_edges:
        if union(parent, rank, u, v):
            blue_count += 1

    for u, v in red_edges:
        union(parent, rank, u, v)

    # Check if the graph is connected
    root = find(parent, 1)
    for i in range(2, n + 1):
        if find(parent, i) != root:
            return 0  # Graph is not connected

    # Count minimum possible blue edges in MST
    parent = list(range(n + 1))
    rank = [0] * (n + 1)

    red_count = 0
    for u, v in red_edges:
        if union(parent, rank, u, v):
            red_count += 1

    for u, v in blue_edges:
        union(parent, rank, u, v)

    # Check if the graph is connected
    root = find(parent, 1)
    for i in range(2, n + 1):
        if find(parent, i) != root:
            return 0  # Graph is not connected

    min_blue = n - 1 - red_count
    max_blue = blue_count

    # Check if k is in the valid range
    return 1 if min_blue <= k <= max_blue else 0

def min_error_after_operations(n: int, k1: int, k2: int, a: list, b: list) -> int:
    r = sorted([abs(a[i] - b[i]) for i in range(n)], reverse=True)
    for it in range(k1 + k2):
        if r[0] == 0:
            r[0] = 1
        else:
            r[0] -= 1
            for i in range(n - 1):
                if r[i] < r[i + 1]:
                    r[i], r[i + 1] = r[i + 1], r[i]
    return sum(x**2 for x in r)

def minimal_magic_path(n: int, edges: list, magic_values: list) -> str:
    import math
    from collections import defaultdict

    # Create adjacency list representation of the tree
    graph = defaultdict(list)
    for a, b in edges:
        graph[a].append(b)
        graph[b].append(a)

    # If tree has only one node, return its magic as a fraction
    if n == 1:
        return f"{magic_values[0]}/1"

    # For a single node path, the magic is just the node's magic
    min_magic_num = min(magic_values)
    min_magic_den = 1

    # For paths with multiple nodes
    for i in range(n):
        for j in range(i+1, n):
            # Find path between nodes i+1 and j+1 (converting to 1-indexed)
            path = find_path(graph, i+1, j+1)

            if path:
                # Calculate path magic
                product = 1
                for node in path:
                    product *= magic_values[node-1]  # Convert to 0-indexed for magic_values

                path_len = len(path)

                # Compare with current minimum magic
                if product * min_magic_den < min_magic_num * path_len:
                    min_magic_num = product
                    min_magic_den = path_len

    # Reduce the fraction
    gcd = math.gcd(min_magic_num, min_magic_den)
    return f"{min_magic_num // gcd}/{min_magic_den // gcd}"

def find_path(graph, start, end, visited=None, path=None):
    if visited is None:
        visited = set()
    if path is None:
        path = []

    visited.add(start)
    path.append(start)

    if start == end:
        return path

    for neighbor in graph[start]:
        if neighbor not in visited:
            result = find_path(graph, neighbor, end, visited, path)
            if result:
                return result

    path.pop()
    return None

def longest_race_path(n: int, edges: list[list[int]]) -> int:
    # Build adjacency list
    graph = [[] for _ in range(n+1)]
    for a, b in edges:
        graph[a].append(b)
        graph[b].append(a)

    # Identify bridges (roads that are not part of any ring)
    visited = [False] * (n+1)
    disc = [float('inf')] * (n+1)
    low = [float('inf')] * (n+1)
    parent = [-1] * (n+1)
    bridges = set()

    def dfs_bridge(u, time):
        nonlocal visited, disc, low, parent, bridges
        visited[u] = True
        disc[u] = low[u] = time
        time += 1

        for v in graph[u]:
            if not visited[v]:
                parent[v] = u
                dfs_bridge(v, time)
                low[u] = min(low[u], low[v])

                if low[v] > disc[u]:
                    bridges.add((min(u, v), max(u, v)))
            elif v != parent[u]:
                low[u] = min(low[u], disc[v])

    for i in range(1, n+1):
        if not visited[i]:
            dfs_bridge(i, 0)

    # Find the longest path ending at city 1
    visited_edge = set()
    max_length = [0]

    def dfs_path(node, length):
        nonlocal visited_edge, max_length

        if node == 1 and length > 0:
            max_length[0] = max(max_length[0], length)

        for neighbor in graph[node]:
            edge = (min(node, neighbor), max(node, neighbor))
            if edge not in visited_edge:
                visited_edge.add(edge)
                dfs_path(neighbor, length + 1)
                visited_edge.remove(edge)

    # Start DFS from each node
    for i in range(1, n+1):
        dfs_path(i, 0)

    return max_length[0]

def min_time_river_crossing(P: int, R: int, L: int, logs: list) -> str:
    from collections import defaultdict, deque

    # Build the graph
    graph = defaultdict(list)
    for u, v in logs:
        graph[u].append(v)
        graph[v].append(u)

    # Check if right bank is reachable from left bank
    def is_reachable():
        visited = set()
        queue = deque([-2])  # Start from left bank
        visited.add(-2)

        while queue:
            node = queue.popleft()
            if node == -1:  # Reached right bank
                return True

            for neighbor in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)

        return False

    # If right bank is not reachable, all people are left behind
    if not is_reachable():
        return f"{P} people left behind"

    # Find the maximum number of disjoint paths from left to right bank
    def max_flow():
        def bfs():
            visited = {-2: None}
            queue = deque([-2])

            while queue and -1 not in visited:
                node = queue.popleft()
                for neighbor in graph[node]:
                    if neighbor not in visited and (node, neighbor) in edges:
                        visited[neighbor] = node
                        queue.append(neighbor)

            return visited

        # Initialize the edges with capacity 1
        edges = set()
        for u in graph:
            for v in graph[u]:
                edges.add((u, v))

        flow = 0
        path_lengths = []

        while flow < P:
            visited = bfs()
            if -1 not in visited:
                break

            # Trace the path
            path = []
            node = -1
            while node != -2:
                prev = visited[node]
                path.append((prev, node))
                node = prev

            # Remove the edges used in this path
            for u, v in path:
                edges.remove((u, v))

            flow += 1
            path_lengths.append(len(path))

        return flow, path_lengths

    max_people, path_lengths = max_flow()

    if max_people < P:
        return f"{P - max_people} people left behind"

    # Calculate the minimum time for all people to cross
    total_time = 0
    for i in range(min(P, max_people)):
        total_time += path_lengths[i]

    return str(total_time)

def min_airport_lounges(n: int, routes: list) -> str:
    # This is a 2-coloring problem (bipartite graph)
    # For each route:
    # - If c=0: both airports should have no lounges
    # - If c=1: exactly one airport should have a lounge
    # - If c=2: both airports should have lounges

    # Initialize graph representation
    graph = [[] for _ in range(n+1)]

    # Process routes with c=1 (exactly one lounge)
    for a, b, c in routes:
        if c == 1:
            graph[a].append(b)
            graph[b].append(a)

    # Check if graph is bipartite (2-colorable)
    color = [0] * (n+1)  # 0: uncolored, 1: color 1, -1: color 2

    def dfs(node, c):
        color[node] = c
        for neighbor in graph[node]:
            if color[neighbor] == 0:
                if not dfs(neighbor, -c):
                    return False
            elif color[neighbor] == c:
                return False
        return True

    # Color the graph
    for i in range(1, n+1):
        if color[i] == 0:
            if not dfs(i, 1):
                return "impossible"

    # Check if the coloring satisfies routes with c=0 and c=2
    for a, b, c in routes:
        if c == 0 and (color[a] == 1 or color[b] == 1):
            return "impossible"
        if c == 2 and (color[a] == -1 or color[b] == -1):
            return "impossible"

    # Count the minimum number of lounges needed
    lounges = sum(1 for i in range(1, n+1) if color[i] == 1)

    return str(lounges)

def reconstruct_manuscript(fragments: list[str]) -> str:
    # Find all possible overlaps between fragments
    overlaps = {}
    for i, frag1 in enumerate(fragments):
        for j, frag2 in enumerate(fragments):
            if i != j:
                # Check for overlap of at least 5 characters
                for k in range(5, min(len(frag1), len(frag2)) + 1):
                    if frag1[-k:] == frag2[:k]:
                        if i not in overlaps:
                            overlaps[i] = []
                        overlaps[i].append((j, k))
                        break

    # Find all possible paths using DFS
    def dfs(node, path, used):
        new_path = path + [node]
        new_used = used.copy()
        new_used.add(node)

        if node in overlaps:
            for next_node, _ in overlaps[node]:
                if next_node not in used:
                    yield from dfs(next_node, new_path, new_used)

        yield new_path

    # Find all maximal paths
    all_paths = []
    for start in range(len(fragments)):
        for path in dfs(start, [], set()):
            all_paths.append(path)

    # Find the paths with maximum length
    max_length = max(len(path) for path in all_paths)
    max_paths = [path for path in all_paths if len(path) == max_length]

    if len(max_paths) > 1:
        return "AMBIGUOUS"

    # Reconstruct the text from the unique maximal path
    path = max_paths[0]
    result = fragments[path[0]]

    for i in range(1, len(path)):
        prev_idx = path[i-1]
        curr_idx = path[i]

        # Find the overlap length
        overlap_length = 0
        for next_idx, length in overlaps.get(prev_idx, []):
            if next_idx == curr_idx:
                overlap_length = length
                break

        # Append the non-overlapping part
        result += fragments[curr_idx][overlap_length:]

    return result

def count_purchasable_houses(L: str, R: str) -> int:
    MOD = 10**9 + 7

    # Check if a number is purchasable
    def is_purchasable(num_str):
        if '4' in num_str:
            return False

        lucky_count = 0  # Count of 6 and 8
        for digit in num_str:
            if digit in '68':
                lucky_count += 1

        # Check if lucky digits count equals non-lucky digits count
        return lucky_count == len(num_str) - lucky_count

    # Convert string inputs to integers
    L_int = int(L)
    R_int = int(R)

    # Count purchasable houses
    count = 0
    for num in range(L_int, R_int + 1):
        if is_purchasable(str(num)):
            count += 1

    return count % MOD

def shortest_travel_time(cities):
    import heapq

    n = len(cities)
    start_y, start_d, start_r = cities[0]

    # Initialize distances with infinity
    dist = [float('inf')] * n
    dist[0] = 0

    # Priority queue for Dijkstra's algorithm
    pq = [(0, 0)]  # (time, city_index)

    while pq:
        time, city = heapq.heappop(pq)

        if time > dist[city]:
            continue

        y_i, d_i, r_i = cities[city]

        for next_city in range(n):
            if next_city == city:
                continue

            y_j = cities[next_city][0]

            # Check if direct flight is possible
            if abs(y_i - y_j) >= d_i:
                new_time = time + r_i + abs(y_i - y_j)

                if new_time < dist[next_city]:
                    dist[next_city] = new_time
                    heapq.heappush(pq, (new_time, next_city))

    # Convert infinite distances to -1
    result = []
    for i in range(1, n):
        if dist[i] == float('inf'):
            result.append(-1)
        else:
            result.append(dist[i])

    return result

def calculate_walk_value(walks: str) -> int:
    MOD = 10**9 + 7

    # dp[i][j] = sum of values when we're at position i in the pattern and node j
    dp = {}

    def dfs(pos, node):
        if pos == len(walks):
            return node

        if (pos, node) in dp:
            return dp[(pos, node)]

        result = 0
        if walks[pos] == 'L' or walks[pos] == '*':
            result += dfs(pos + 1, 2 * node)

        if walks[pos] == 'R' or walks[pos] == '*':
            result += dfs(pos + 1, 2 * node + 1)

        if walks[pos] == 'P' or walks[pos] == '*':
            result += dfs(pos + 1, node)

        dp[(pos, node)] = result
        return result

    return dfs(0, 1)

def win_probability(n: int, m: int, probabilities: list[float]) -> float:
    # Create a 2D DP array to store probabilities
    # dp[i][j] = probability Anthony wins when he has i points and Cora has j points
    dp = [[0.0] * (m + 1) for _ in range(n + 1)]

    # Base cases: Anthony wins when Cora has 0 points
    for i in range(1, n + 1):
        dp[i][0] = 1.0

    # Base cases: Anthony loses when he has 0 points and Cora has > 0
    for j in range(1, m + 1):
        dp[0][j] = 0.0

    # Fill the DP table
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            # Get the probability for this round
            round_idx = (n + m) - (i + j)
            if round_idx < len(probabilities):
                p = probabilities[round_idx]
            else:
                p = 0.5  # Default if not enough probabilities provided

            # Anthony wins with probability p, Cora loses a point
            # Anthony loses with probability (1-p), Anthony loses a point
            dp[i][j] = p * dp[i][j-1] + (1-p) * dp[i-1][j]

    return dp[n][m]

def calculate_player_spreads(board: list[str]) -> tuple[int, int]:
    # Find positions of all M and S pieces
    mirko_positions = []
    slavko_positions = []

    for i in range(len(board)):
        for j in range(len(board[i])):
            if board[i][j] == 'M':
                mirko_positions.append((i, j))
            elif board[i][j] == 'S':
                slavko_positions.append((i, j))

    # Calculate spread for Mirko
    mirko_spread = 0
    for i in range(len(mirko_positions)):
        for j in range(i + 1, len(mirko_positions)):
            r1, c1 = mirko_positions[i]
            r2, c2 = mirko_positions[j]
            distance = max(abs(r1 - r2), abs(c1 - c2))
            mirko_spread += distance

    # Calculate spread for Slavko
    slavko_spread = 0
    for i in range(len(slavko_positions)):
        for j in range(i + 1, len(slavko_positions)):
            r1, c1 = slavko_positions[i]
            r2, c2 = slavko_positions[j]
            distance = max(abs(r1 - r2), abs(c1 - c2))
            slavko_spread += distance

    return (mirko_spread, slavko_spread)

def count_wonderful_rectangles(k: int, n: int) -> int:
    # Function to check if a number is prime
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    # Function to get the number of rocks for the nth lawn
    def get_rocks(k, n):
        if n == 1:
            return 42
        if n == 2:
            return 11 * k + 77

        a, b = 42, 11 * k + 77
        for i in range(3, n + 1):
            a, b = b, 2 * b - a + 10 * k
        return b

    # Function to check if a number can form a wonderful rectangle
    def can_form_wonderful_rectangle(num):
        for p in range(2, int(num**0.5) + 1):
            if num % p == 0:
                q = num // p
                if is_prime(p) and is_prime(q):
                    return True
        return False

    # Count lawns where wonderful rectangles can be formed
    count = 0
    for i in range(1, n + 1):
        rocks = get_rocks(k, i)
        if can_form_wonderful_rectangle(rocks):
            count += 1

    return count

def find_good_nodes(n: int, edges: list) -> list:
    # Build the adjacency list and store colors
    graph = [[] for _ in range(n + 1)]
    for a, b, c in edges:
        graph[a].append((b, c))
        graph[b].append((a, c))

    # Check if a node is good
    def is_good(node):
        visited = [False] * (n + 1)

        def dfs(current, parent, last_color):
            visited[current] = True

            for neighbor, color in graph[current]:
                if neighbor != parent:
                    # Check if this edge's color is the same as the last edge's color
                    if color == last_color:
                        return False

                    # Continue DFS
                    if not dfs(neighbor, current, color):
                        return False

            return True

        # Try all possible paths starting from this node
        for neighbor, color in graph[node]:
            visited[node] = True
            if not dfs(neighbor, node, color):
                return False
            # Reset visited for next path
            visited = [False] * (n + 1)

        return True

    # Find all good nodes
    good_nodes = []
    for i in range(1, n + 1):
        if is_good(i):
            good_nodes.append(i)

    return good_nodes

def min_riders_needed(beacons, mountains):
    def can_see(beacon1, beacon2):
        x1, y1 = beacon1
        x2, y2 = beacon2

        for mx, my, r in mountains:
            # Check if the line between the two beacons passes through the mountain
            # First, find the closest point on the line to the mountain center
            dx, dy = x2 - x1, y2 - y1
            len_squared = dx**2 + dy**2

            # Calculate the projection of the vector from (x1,y1) to (mx,my) onto the line
            t = max(0, min(1, ((mx - x1) * dx + (my - y1) * dy) / len_squared))

            # Find the closest point on the line segment
            closest_x = x1 + t * dx
            closest_y = y1 + t * dy

            # Check if this closest point is within the mountain
            dist_squared = (closest_x - mx)**2 + (closest_y - my)**2
            if dist_squared < r**2:
                return False

        return True

    # Build an adjacency list for the beacons
    n = len(beacons)
    graph = [[] for _ in range(n)]

    for i in range(n):
        for j in range(i+1, n):
            if can_see(beacons[i], beacons[j]):
                graph[i].append(j)
                graph[j].append(i)

    # Find connected components using DFS
    visited = [False] * n

    def dfs(node):
        visited[node] = True
        for neighbor in graph[node]:
            if not visited[neighbor]:
                dfs(neighbor)

    components = 0
    for i in range(n):
        if not visited[i]:
            components += 1
            dfs(i)

    # The number of riders needed is one less than the number of connected components
    return max(0, components - 1)

def find_carryless_square_root(N: str) -> str:
    def carryless_add(a, b):
        """Perform carryless addition of two numbers in base 10"""
        result = ""
        for i in range(max(len(a), len(b))):
            digit_a = int(a[len(a) - 1 - i]) if i < len(a) else 0
            digit_b = int(b[len(b) - 1 - i]) if i < len(b) else 0
            result = str((digit_a + digit_b) % 10) + result
        return result

    def carryless_multiply(a, b):
        """Perform carryless multiplication of two numbers in base 10"""
        partial_products = []
        for i in range(len(b)):
            partial = ""
            for j in range(len(a)):
                digit_a = int(a[len(a) - 1 - j])
                digit_b = int(b[len(b) - 1 - i])
                partial = str((digit_a * digit_b) % 10) + partial
            partial_products.append(partial + "0" * i)

        result = "0"
        for product in partial_products:
            result = carryless_add(result, product)

        # Remove leading zeros
        return result.lstrip("0") or "0"

    def carryless_square(a):
        """Compute a ⊗ a"""
        return carryless_multiply(a, a)

    # Try all numbers starting from 1
    a = 1
    while len(str(a)) <= (len(N) + 1) // 2:  # Square root cannot be longer than half the target (plus 1 for odd lengths)
        a_str = str(a)
        square = carryless_square(a_str)
        if square == N:
            return a_str
        a += 1

    return "-1"

def max_mission_success_probability(probabilities):
    n = len(probabilities)

    # Convert percentages to probabilities
    for i in range(n):
        for j in range(n):
            probabilities[i][j] /= 100

    # Function to find the maximum probability using recursion and memoization
    memo = {}

    def find_max_probability(mask, mission):
        if mission == n:
            return 1.0

        if (mask, mission) in memo:
            return memo[(mask, mission)]

        max_prob = 0
        for bond in range(n):
            if (mask & (1 << bond)) == 0:  # If bond is not assigned yet
                prob = probabilities[bond][mission] * find_max_probability(mask | (1 << bond), mission + 1)
                max_prob = max(max_prob, prob)

        memo[(mask, mission)] = max_prob
        return max_prob

    # Calculate the maximum probability and convert back to percentage
    return find_max_probability(0, 0) * 100

def max_blue_lemonade(n: int, trades: list) -> float:
    # Initialize dictionary to track maximum amount of each lemonade
    lemonades = {"pink": 1.0}

    for offered, wanted, rate in trades:
        # If we have the lemonade that this child wants
        if wanted in lemonades:
            # Calculate how much of the offered lemonade we can get
            amount_offered = lemonades[wanted] * rate

            # Update the maximum amount for the offered lemonade
            if offered in lemonades:
                lemonades[offered] = max(lemonades[offered], amount_offered)
            else:
                lemonades[offered] = amount_offered

    # Return the amount of blue lemonade, or 0 if we couldn't get any
    result = lemonades.get("blue", 0.0)

    # Cap at 10 litres
    return min(result, 10.0)

def determine_character_types(debate_transcript: str) -> str:
    lines = debate_transcript.strip().split('\n')
    n, k = map(int, lines[0].split())

    statements = []
    for i in range(1, k+1):
        parts = lines[i].split(' ', 1)
        speaker = int(parts[0])
        statement = parts[1]
        statements.append((speaker, statement))

    # Try all possible assignments of character types
    for assignment in generate_all_assignments(n):
        if is_valid_assignment(assignment, statements):
            return '\n'.join(assignment)

    return "No valid assignment found"

def generate_all_assignments(n):
    """Generate all possible assignments of character types for n candidates."""
    types = ['truther', 'fabulist', 'charlatan']

    def generate_helper(current, remaining):
        if remaining == 0:
            yield current
            return
        for t in types:
            yield from generate_helper(current + [t], remaining - 1)

    return generate_helper([], n)

def is_valid_assignment(assignment, statements):
    """Check if an assignment of character types is valid for the given statements."""
    speakers_statements = {}
    for speaker, statement in statements:
        if speaker not in speakers_statements:
            speakers_statements[speaker] = []
        speakers_statements[speaker].append(statement)

    for speaker, stmts in speakers_statements.items():
        speaker_type = assignment[speaker-1]

        if speaker_type == 'truther':
            # All statements must be true
            for stmt in stmts:
                if not evaluate_statement(stmt, assignment):
                    return False

        elif speaker_type == 'fabulist':
            # All statements must be false
            for stmt in stmts:
                if evaluate_statement(stmt, assignment):
                    return False

        elif speaker_type == 'charlatan':
            # Must be a switch from true to false
            found_switch = False
            prev_truth_value = True

            for stmt in stmts:
                curr_truth_value = evaluate_statement(stmt, assignment)

                # If we were true before and now false, mark the switch
                if prev_truth_value and not curr_truth_value:
                    found_switch = True

                # If we already switched and now see a true statement, invalid
                if found_switch and curr_truth_value:
                    return False

                prev_truth_value = curr_truth_value

            # Must have at least one true and one false statement
            if not found_switch:
                return False

    return True

def evaluate_statement(statement, assignment):
    """Evaluate if a statement is true given the assignment of character types."""
    tokens = tokenize_statement(statement)
    return evaluate_tokens(tokens, 0, assignment)[0]

def tokenize_statement(statement):
    """Convert a statement string into tokens."""
    return statement.split()

def evaluate_tokens(tokens, index, assignment):
    """Evaluate tokens recursively, returning the value and the new index."""
    if tokens[index] == 'truther':
        candidate = int(tokens[index+1]) - 1
        return assignment[candidate] == 'truther', index + 2

    elif tokens[index] == 'fabulist':
        candidate = int(tokens[index+1]) - 1
        return assignment[candidate] == 'fabulist', index + 2

    elif tokens[index] == 'charlatan':
        candidate = int(tokens[index+1]) - 1
        return assignment[candidate] == 'charlatan', index + 2

    elif tokens[index] == 'not':
        value, new_index = evaluate_tokens(tokens, index+1, assignment)
        return not value, new_index

    elif tokens[index] == 'and':
        value1, new_index = evaluate_tokens(tokens, index+1, assignment)
        value2, final_index = evaluate_tokens(tokens, new_index, assignment)
        return value1 and value2, final_index

    elif tokens[index] == 'xor':
        value1, new_index = evaluate_tokens(tokens, index+1, assignment)
        value2, final_index = evaluate_tokens(tokens, new_index, assignment)
        return value1 != value2, final_index

