def teacher_assignments(n, m, queries):
    # Initialize teacher-to-class mapping
    teacher_to_class = {i: i for i in range(1, n+1)}

    # Dictionary to store rotations by week
    rotations = {}

    results = []

    for query in queries:
        if query[0] == 0:  # Rotation query
            _, k, week, *teachers = query
            rotations[week] = teachers
        else:  # Assignment query
            _, teacher, week = query

            # Apply all rotations up to the specified week
            current_teacher_to_class = {i: i for i in range(1, n+1)}

            for w in range(1, week+1):
                if w in rotations:
                    rotation_teachers = rotations[w]
                    k = len(rotation_teachers)

                    # Get the classes where the teachers are currently teaching
                    current_classes = [current_teacher_to_class[t] for t in rotation_teachers]

                    # Rotate the classes
                    for i in range(k):
                        current_teacher_to_class[rotation_teachers[i]] = current_classes[(i+1) % k]

            results.append(current_teacher_to_class[teacher])

    return results

def longest_subarray_with_exactly_two_occurrences(arr: list) -> int:
    n = len(arr)
    max_length = 0

    for i in range(n):
        freq = {}
        for j in range(i, n):
            num = arr[j]
            freq[num] = freq.get(num, 0) + 1

            # Check if all elements have exactly 2 occurrences
            all_have_two = True
            for count in freq.values():
                if count != 2:
                    all_have_two = False
                    break

            if all_have_two:
                max_length = max(max_length, j - i + 1)

    return max_length

def lava_game(elsa_step_length: int, father_step_length: int, game_map: list) -> str:
    from collections import deque
    import math

    # Find start and goal positions
    start_pos = None
    goal_pos = None
    rows = len(game_map)
    cols = len(game_map[0])

    for i in range(rows):
        for j in range(len(game_map[i])):
            if game_map[i][j] == 'S':
                start_pos = (i, j)
            elif game_map[i][j] == 'G':
                goal_pos = (i, j)

    # BFS for Elsa
    def elsa_bfs():
        queue = deque([(start_pos, 0)])  # (position, distance)
        visited = {start_pos}

        while queue:
            (x, y), dist = queue.popleft()

            if (x, y) == goal_pos:
                return dist

            for i in range(max(0, x - elsa_step_length), min(rows, x + elsa_step_length + 1)):
                for j in range(max(0, y - elsa_step_length), min(cols, y + elsa_step_length + 1)):
                    if (i, j) not in visited and (game_map[i][j] == 'W' or game_map[i][j] == 'G'):
                        # Check if within Elsa's reach (Euclidean distance)
                        if math.sqrt((i - x) ** 2 + (j - y) ** 2) <= elsa_step_length:
                            queue.append(((i, j), dist + 1))
                            visited.add((i, j))

        return float('inf')  # Cannot reach goal

    # BFS for Father
    def father_bfs():
        queue = deque([(start_pos, 0)])  # (position, distance)
        visited = {start_pos}

        while queue:
            (x, y), dist = queue.popleft()

            if (x, y) == goal_pos:
                return dist

            # Father can only move along the axes
            for dx in range(-father_step_length, father_step_length + 1):
                # Horizontal movement
                nx, ny = x + dx, y
                if 0 <= nx < rows and 0 <= ny < cols and (nx, ny) not in visited and (game_map[nx][ny] == 'W' or game_map[nx][ny] == 'G'):
                    queue.append(((nx, ny), dist + 1))
                    visited.add((nx, ny))

            for dy in range(-father_step_length, father_step_length + 1):
                # Vertical movement
                nx, ny = x, y + dy
                if 0 <= nx < rows and 0 <= ny < cols and (nx, ny) not in visited and (game_map[nx][ny] == 'W' or game_map[nx][ny] == 'G'):
                    queue.append(((nx, ny), dist + 1))
                    visited.add((nx, ny))

        return float('inf')  # Cannot reach goal

    elsa_steps = elsa_bfs()
    father_steps = father_bfs()

    if elsa_steps == float('inf') and father_steps == float('inf'):
        return "NO WAY"
    elif elsa_steps < father_steps:
        return "GO FOR IT"
    elif father_steps < elsa_steps:
        return "NO CHANCE"
    else:
        return "SUCCESS"

def max_flowers_visited(N: int, R: int, C: int, field: list[list[int]]) -> int:
    # Convert 1-indexed to 0-indexed for R and C
    R -= 1
    C -= 1

    # Using memoization to avoid recalculating
    memo = {}

    def dfs(r, c):
        if (r, c) in memo:
            return memo[(r, c)]

        max_flowers = 1  # Count the current flower

        # Check all possible jumps
        for new_r in range(N):
            for new_c in range(N):
                # Check if this is a valid jump according to the rules
                if ((abs(r - new_r) == 1 and abs(c - new_c) > 1) or 
                    (abs(c - new_c) == 1 and abs(r - new_r) > 1)):
                    # Check if the new flower has more petals
                    if field[new_r][new_c] > field[r][c]:
                        max_flowers = max(max_flowers, 1 + dfs(new_r, new_c))

        memo[(r, c)] = max_flowers
        return max_flowers

    return dfs(R, C)

def determine_winner(points):
    # Group points by their x and y coordinates
    x_groups = {}
    y_groups = {}

    for x, y in points:
        if x not in x_groups:
            x_groups[x] = []
        if y not in y_groups:
            y_groups[y] = []

        x_groups[x].append((x, y))
        y_groups[y].append((x, y))

    # Count the number of lines with exactly one point
    single_lines = 0

    for x in x_groups:
        if len(x_groups[x]) == 1:
            single_lines += 1

    for y in y_groups:
        if len(y_groups[y]) == 1:
            single_lines += 1

    # Determine the winner based on the parity of single lines
    if single_lines % 2 == 1:
        return "Mirko"
    else:
        return "Slavko"

def min_tunnel_cost(planets):
    import heapq

    def tunnel_cost(p1, p2):
        return min(abs(p1[0] - p2[0]), abs(p1[1] - p2[1]), abs(p1[2] - p2[2]))

    n = len(planets)
    if n <= 1:
        return 0

    # Prim's algorithm to find minimum spanning tree
    visited = [False] * n
    visited[0] = True
    edges = []

    for i in range(1, n):
        heapq.heappush(edges, (tunnel_cost(planets[0], planets[i]), i))

    total_cost = 0
    count = 1  # Number of planets connected

    while count < n:
        cost, next_planet = heapq.heappop(edges)

        if not visited[next_planet]:
            visited[next_planet] = True
            total_cost += cost
            count += 1

            for i in range(n):
                if not visited[i]:
                    heapq.heappush(edges, (tunnel_cost(planets[next_planet], planets[i]), i))

    return total_cost

